mapper.select:
select mr.record_id,
       mr.encounter_id,
       e.patient_id,
       e.doctor_id,
       mr.chief_complaint,
       mr.present_illness,
       mr.past_history,
       mr.allergy_history,
       mr.physical_exam,
       mr.diagnosis_opinion,
       mr.treatment_plan,
       mr.doctor_advice,
       mr.create_time,
       mr.update_time,
       d.doctor_name,
       sd.dept_name,
       e.encounter_type,
       e.visit_time
from medical_record mr
left join encounter e on e.encounter_id = mr.encounter_id
left join doctor d on d.doctor_id = e.doctor_id
left join sys_dept sd on sd.dept_id = e.dept_id

     and e.patient_id = #{patientId}
     and e.doctor_id = #{doctorId}
     and mr.encounter_id = #{encounterId}
     and mr.chief_complaint = #{chiefComplaint}
     and mr.present_illness = #{presentIllness}
     and mr.past_history = #{pastHistory}
     and mr.allergy_history = #{allergyHistory}
     and mr.physical_exam = #{physicalExam}
     and mr.diagnosis_opinion = #{diagnosisOpinion}
     and mr.treatment_plan = #{treatmentPlan}
     and mr.doctor_advice = #{doctorAdvice}

order by mr.create_time desc, mr.record_id desc

mapper.update:
update medical_record
encounter_id = #{encounterId}, chief_complaint = #{chiefComplaint}, present_illness = #{presentIllness}, past_history = #{pastHistory}, allergy_history = #{allergyHistory}, physical_exam = #{physicalExam}, diagnosis_opinion = #{diagnosisOpinion}, treatment_plan = #{treatmentPlan}, doctor_advice = #{doctorAdvice}, create_time = #{createTime}, update_time = #{updateTime},
where record_id = #{recordId}
